const ITEMS = {};
const RESTAURANTS = RAW.map(r => {
  const grad = mkGrad(r.color);
  const menu = r.menu.map((m, i) => {
    const item = { ...m, id: `${r.id}_${i}`, rid: r.id };
    ITEMS[item.id] = item;
    return item;
  });
  // Price tier (1=₱, 2=₱₱, 3=₱₱₱) from average menu price.
  const avg = menu.reduce((sum, m) => sum + m.price, 0) / menu.length;
  const priceLevel = avg < 100 ? 1 : avg < 160 ? 2 : 3;
  return { ...r, grad, menu, priceLevel };
});
export { RESTAURANTS, ITEMS };
